import sys

def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    t=int(data[0])
    idx=1
    out=[]
    for _ in range(t):
        x=int(data[idx]); y=int(data[idx+1]); idx+=2
        ch=2*x
        ca=5*y
        if ch>ca:
            out.append('Chocolate')
        elif ch<ca:
            out.append('Candy')
        else:
            out.append('Either')
    sys.stdout.write('
'.join(out))

if __name__=='__main__':
    solve()

